        ]

    def action_save_mail_column_template(self):
        self.ensure_one()
        name = (self.new_template_name or "").strip()
        if not name:
            raise UserError(_("Enter a template name."))
        lines = self.column_line_ids.sorted("sequence")
        if not lines:
            raise UserError(_("Add at least one column before saving."))
        keys = [l.column_key for l in lines]
        if len(keys) != len(set(keys)):
            raise UserError(_("Each column can only appear once."))
        Template = self.env["daily.search.email_bid_mail_column_template"]
        template = Template.create(
            {
                "name": name,
                "line_ids": [
                    (0, 0, {"sequence": l.sequence, "column_key": l.column_key})
                    for l in lines
                ],
            }
        )
        self.mail_column_template_id = template
        self.new_template_name = False
        return {
            "type": "ir.actions.client",
            "tag": "display_notification",
            "params": {
                "title": _("Template saved"),
                "message": name,
                "type": "success",
                "sticky": False,
            },
        }

    def action_send_bid_unassigned_email(self):
        self.ensure_one()
        if not self.recipient_employee_ids:
            raise UserError(_("Please select at least one employee recipient."))
        if not self.lead_ids:
            raise UserError(_("No leads are selected to be emailed."))
        column_keys = self._get_ordered_column_keys()
        if not column_keys:
            raise UserError(_("Add at least one column to include in the email."))
        if len(column_keys) != len(set(column_keys)):
            raise UserError(_("Each column can only appear once in the list."))

        recipient_emails = []
        for emp in self.recipient_employee_ids:
            email = (emp.work_email or "").strip()
            if not email:
                raise UserError(
                    _(
                        "Employee %(name)s has no work email. Set work email or pick another recipient.",
                        name=emp.display_name,
                    )
                )
            recipient_emails.append(email)

        import html as _html
        today = datetime.date.today().strftime("%Y-%m-%d")
        email_subject = f"Bid-marked leads — vetting queue — {today}"
        inner_table = build_bid_unassigned_email_html(self.lead_ids, column_keys=column_keys)
        notes_html = ""
        if self.notes and self.notes.strip():
            escaped = _html.escape(self.notes.strip()).replace("\n", "<br/>")
            notes_html = f"<p>{escaped}</p>"
        email_body = f"""
        <html>
        <body>
        <p><strong>THIS IS AN AUTOMATED MESSAGE</strong></p>
        <p>Hello,</p>
        <p><strong>Bid-marked</strong> leads on deck for vetting: still need a company area and are not in CRM or on a project yet.
        Details below match your Daily Search list.</p>
        {notes_html}
        {inner_table}
        <p>Thank you.</p>
        </body>
        </html>
        """

        try:
            from .graph_client import GraphClient

            client = GraphClient(self.env)
            send_mail_endpoint = f"/users/{client.mail_acg}/sendMail"
            email_payload = {
                "message": {
                    "subject": email_subject,
                    "body": {"contentType": "HTML", "content": email_body},
                    "toRecipients": [
                        {"emailAddress": {"address": email}} for email in recipient_emails
                    ],
                },
                "saveToSentItems": "true",
            }
            client.call_api("POST", send_mail_endpoint, payload=email_payload)
            LOG.info(
                "Sent bid unassigned lead email to: %s",
                ", ".join(recipient_emails),
            )
            LOG.summary(
                "Bid unassigned email: lead_count=%s recipient_count=%s",
                len(self.lead_ids),
                len(recipient_emails),
            )
        except Exception as e:
            LOG.error(
                "Failed to send bid unassigned email: lead_count=%s error=%s",
                len(self.lead_ids),
                e,
            )
            raise UserError(_("Failed to send email. Check logs for details. Error: %s") % e) from e

        return {"type": "ir.actions.act_window_close"}

