/* Hide EMAIL, SMS, and SNOOZE action buttons in CRM list view */
.o_list_table.o_list_table_ungrouped tbody tr td.o_list_button {
    display: none !important;
}

/* Hide activity snooze and other action cells */
.o_list_view[data-model="crm.lead"] .o_list_table tbody tr td.o_list_button,
.o_list_view[data-model="crm.lead"] .o_list_table tbody tr td.w-print-0.p-print-0.cursor-pointer {
    display: none !important;
}

/* Hide activity widget action buttons */
.o_list_view[data-model="crm.lead"] .o_activity_cell .o_activity_action {
    display: none !important;
}

/* Hide all action button cells in CRM - multiple selectors for maximum coverage */
.o_list_view[data-model="crm.lead"] .o_data_cell.o_list_button,
.o_list_view[data-model="crm.lead"] td.o_list_button,
.o_list_view[data-model="crm.lead"] td.cursor-pointer.o_list_button,
.o_list_view[data-model="crm.lead"] .o_list_table td.o_data_cell.cursor-pointer.o_list_button {
    display: none !important;
    visibility: hidden !important;
    width: 0 !important;
    height: 0 !important;
    padding: 0 !important;
    margin: 0 !important;
    overflow: hidden !important;
}

/* Hide action buttons in grouped views */
.o_list_view[data-model="crm.lead"] .o_list_table_grouped .o_list_button,
.o_list_view[data-model="crm.lead"] .o_list_table_grouped td.o_data_cell.cursor-pointer,
.o_list_view[data-model="crm.lead"] td.cursor-pointer.o_list_button {
    display: none !important;
}

/* Hide Email, SMS, Snooze buttons and their parent divs */
.o_list_view[data-model="crm.lead"] button[name="378"],
.o_list_view[data-model="crm.lead"] button[name="598"],
.o_list_view[data-model="crm.lead"] button[name="action_snooze"],
.o_list_view[data-model="crm.lead"] .d-flex.flex-wrap.gap-1:has(button[name="378"]) {
    display: none !important;
}

/* Name column width: target th[data-name="name"] because Odoo 18 does NOT add the class to <th>,
   only to <td>. With table-layout:fixed the <th> inline style="width:89px" drives the column —
   !important in a stylesheet overrides inline styles. */
.o_list_view[data-model="crm.lead"] th[data-name="name"] {
    min-width: 400px !important;
    width: 400px !important;
    max-width: 400px !important;
}

/* <td> text clamping: class IS present here */
.o_list_view[data-model="crm.lead"] td.o_crm_opportunity_name_limited {
    min-width: 400px !important;
    max-width: 400px !important;
    width: 400px !important;
    white-space: normal !important;
    display: -webkit-box !important;
    -webkit-line-clamp: 2 !important;
    -webkit-box-orient: vertical !important;
    overflow: hidden !important;
    text-overflow: ellipsis !important;
    line-height: 1.4em !important;
    max-height: 2.8em !important;
}

/* Red background for rows with dates within next 7 days */
.o_list_view[data-model="crm.lead"] .o_data_row.text-bf {
    background-color: #ffebee !important;
}

.o_list_view[data-model="crm.lead"] .o_data_row.text-bf:hover {
    background-color: #ffcdd2 !important;
}

